const bills = $input.first().json.data || [];
const results = [];

const today = new Date();
today.setHours(0, 0, 0, 0);
const msPerDay = 24 * 60 * 60 * 1000;

for (const bill of bills) {
  const balance = Number(bill.balance || 0);
  if (balance <= 0) continue;

  // Use noon UTC to avoid off-by-one errors caused by timezone offsets on the due date string
  const dueDate = new Date(bill.due_at + 'T12:00:00Z');
  dueDate.setHours(0, 0, 0, 0);
  const daysOverdue = Math.max(0, Math.floor((today - dueDate) / msPerDay));

  // 2-day windows per step absorb weekends and cron timing drift
  let ladder_step = 'none';
  if      (daysOverdue >= 1  && daysOverdue <= 2)  ladder_step = 'day1';
  else if (daysOverdue >= 7  && daysOverdue <= 8)  ladder_step = 'day7';
  else if (daysOverdue >= 14 && daysOverdue <= 15) ladder_step = 'day14';
  else if (daysOverdue >= 30 && daysOverdue <= 31) ladder_step = 'day30';
  else if (daysOverdue >= 60)                       ladder_step = 'day60';

  if (ladder_step === 'none') continue;

  results.push({
    json: {
      invoice_id:     bill.id,
      invoice_number: bill.number,
      due_date:       bill.due_at,
      days_overdue:   daysOverdue,
      balance:        balance,
      total:          Number(bill.total || 0),
      client_name:    bill.client?.name  || '',
      client_email:   bill.client?.email || '',
      matter_id:      bill.matter?.id                 || '',
      matter_ref:     bill.matter?.display_number     || '',
      share_url:      bill.share_url || '',
      ladder_step,
      is_actionable:  true
    }
  });
}

if (results.length === 0) {
  return [{ json: { is_actionable: false, ladder_step: 'none', reason: 'No invoices due for a reminder today' } }];
}

return results;

const invoice = $input.first().json;
const FIRM_NAME      = $vars.FIRM_NAME;
const PARTNER_EMAIL  = $vars.FIRM_PARTNER_EMAIL;
const FROM_EMAIL     = $vars.FIRM_FROM_EMAIL;
const PAY_LINK       = invoice.share_url || $vars.FIRM_PAY_LINK || '';

const subject = `Action required: Invoice ${invoice.invoice_number} is ${invoice.days_overdue} days overdue`;

const body = `An invoice has passed the 60-day threshold and needs your attention.

Client: ${invoice.client_name}
Matter: ${invoice.matter_ref}
Invoice: ${invoice.invoice_number}
Balance due: $${Number(invoice.balance).toFixed(2)}
Original total: $${Number(invoice.total).toFixed(2)}
Due date: ${invoice.due_date}
Days overdue: ${invoice.days_overdue}

Client pay link: ${PAY_LINK}

Recommended next steps:
1. Call the client directly
2. Offer a payment plan if appropriate
3. Refer to collections if no response within 7 days

— ${FIRM_NAME} Billing System`;

return [{
  json: {
    ...invoice,
    partner_email: PARTNER_EMAIL,
    from_email:    FROM_EMAIL,
    subject,
    body
  }
}];

const invoice = $input.first().json;
