${PAY_LINK}

To resolve this immediately, contact us at ${FIRM_EMAIL}.

${FIRM_NAME}`
  }
};

const step = steps[invoice.ladder_step] || steps.day1;

return [{
  json: {
    ...invoice,
    channel:     'email',
    recipient:   invoice.client_email,
    message:     step.body,
    subject:     step.subject,
    template_id: 'PAC-18-invoice-reminder',
    matter_id:   String(invoice.matter_id || '')
  }
}];
